// 월간 리포트: 당월 1일 ~ 말일 기준
// 수행일: 매월 말일 17:00 (당월 데이터 집계)
// cron은 28-31일에 실행되지만, 실제 말일인지 체크하여 말일만 실행

// 한국 시간대 적용
function getKSTDate(date = new Date()) {
  const kstOffset = 9 * 60;
  return new Date(date.getTime() + (kstOffset + date.getTimezoneOffset()) * 60000);
}

function formatDate(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

function formatYearMonth(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  return `${yyyy}-${mm}`;
}

// 해당 월의 마지막 날짜 구하기
function getLastDayOfMonth(year, month) {
  return new Date(year, month + 1, 0).getDate();
}

// 오늘이 말일인지 체크
function isLastDayOfMonth(date) {
  const lastDay = getLastDayOfMonth(date.getFullYear(), date.getMonth());
  return date.getDate() === lastDay;
}

// 당월의 첫째 날 구하기
function getFirstDayOfCurrentMonth(date) {
  const d = new Date(date);
  d.setDate(1);
  return d;
}

const now = getKSTDate();

// 트리거 타입 판별: $execution.mode로 확인
// 'manual' = 수동실행, 'trigger' = 스케줄 트리거
const executionMode = $execution?.mode || 'trigger';
const isManual = executionMode === 'manual';

// Manual 트리거가 아닌 경우 말일 체크 (스케줄 실행 시에만 말일 체크)
const isLastDay = isLastDayOfMonth(now);
const shouldRun = isManual || isLastDay;

// 기준 기간: 당월 1일 ~ 말일 (오늘)
const firstDay = getFirstDayOfCurrentMonth(now);

const PERIOD_START = formatDate(firstDay);
const PERIOD_END = formatDate(now);
const PERIOD_DISPLAY = formatYearMonth(firstDay);

return [{
  json: {
    reportType: 'monthly',
    shouldRun,
    executionMode,
    isManual,
    isLastDay,
    PERIOD_START,
    PERIOD_END,
    PERIOD_DISPLAY,
    executionTime: formatDate(now) + ' ' + now.toTimeString().slice(0, 5)
  }
}];

// 에러 정보 추출 및 포맷팅
const errorData = $input.first().json;

const now = new Date();
const timestamp = now.toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });

const execution = errorData.execution || {};
const workflow = errorData.workflow || {};
const error = execution.error || {};

let failedNode = 'Unknown';
let errorMessage = error.message || 'Unknown error';
let errorStack = '';

if (execution.data && execution.data.resultData) {
  const runData = execution.data.resultData.runData || {};
  const lastNodeExecuted = execution.data.resultData.lastNodeExecuted;

  if (lastNodeExecuted) {
    failedNode = lastNodeExecuted;
  }

  if (error.stack) {
    errorStack = error.stack.substring(0, 500);
  }
}

let errorType = '일반 오류';
if (errorMessage.includes('login') || errorMessage.includes('Login') || errorMessage.includes('session') || errorMessage.includes('cookie')) {
  errorType = '로그인 실패';
} else if (errorMessage.includes('CSRF') || errorMessage.includes('token')) {
  errorType = 'CSRF 토큰 오류';
} else if (errorMessage.includes('Notion') || errorMessage.includes('notion')) {
  errorType = 'Notion API 오류';
} else if (errorMessage.includes('Slack') || errorMessage.includes('slack')) {
  errorType = 'Slack API 오류';
} else if (errorMessage.includes('timeout') || errorMessage.includes('ETIMEDOUT')) {
  errorType = '타임아웃 오류';
} else if (errorMessage.includes('network') || errorMessage.includes('ECONNREFUSED')) {
  errorType = '네트워크 오류';
}

const slackMessage = `🚨 *PMS 월간 리포트 워크플로우 실패*\n\n*발생 시간:* ${timestamp}\n*에러 유형:* ${errorType}\n*실패 노드:* ${failedNode}\n*워크플로우:* ${workflow.name || 'Redmine PMS Monthly Report'}\n\n*에러 메시지:*\n\`\`\`\n${errorMessage}\n\`\`\`${errorStack ? `\n*스택 트레이스:*\n\`\`\`\n${errorStack}\n\`\`\`` : ''}`;

return [{
  json: {
    channel: '#pms-monthly',
    slackMessage,
    errorType,
    failedNode,
    errorMessage,
    timestamp
  }
}];

// 환경변수에서 설정값 가져오기
const REDMINE_BASE_URL = $env.REDMINE_BASE_URL;
if (!REDMINE_BASE_URL) {
  throw new Error('REDMINE_BASE_URL 환경변수가 설정되지 않았습니다.');
}
const REDMINE_USERNAME = $env.REDMINE_USERNAME || '';
const REDMINE_PASSWORD = $env.REDMINE_PASSWORD || '';
const NOTION_DATABASE_ID = $env.NOTION_DATABASE_ID || '';

const periodData = $input.first().json;
const PERIOD_START = periodData.PERIOD_START;
const PERIOD_END = periodData.PERIOD_END;
const PERIOD_DISPLAY = periodData.PERIOD_DISPLAY;
const reportType = periodData.reportType;

return [{
  json: {
    REDMINE_BASE_URL,
    REDMINE_USERNAME,
    REDMINE_PASSWORD,
    NOTION_DATABASE_ID,
    PERIOD_START,
    PERIOD_END,
    PERIOD_DISPLAY,
    reportType,
    SLACK_CHANNELS: ['#pms-monthly'],
    PROJECTS: [
      {
        name: '결함',
        url: `${REDMINE_BASE_URL}/projects/dcim_adv/issues?query_id=1477&per_page=100`
      },
      {
        name: '신규기능개발',
        url: `${REDMINE_BASE_URL}/projects/dcim_adv/issues?query_id=1478&per_page=100`
      },
      {
        name: 'KT cloud',
        url: `${REDMINE_BASE_URL}/projects/dcim_adv/issues?query_id=1486&per_page=100`
      },
      {
        name: '애플망고-사이트지원',
        url: `${REDMINE_BASE_URL}/projects/applemango_site/issues?per_page=100&query_id=1087`
      },
      {
        name: '애플망고-결함처리',
        url: `${REDMINE_BASE_URL}/projects/release_issues_applemango/issues?query_id=1049&per_page=100`
      }
    ]
  }
}];

const inputData = $input.first().json;

let html = '';
let headers = {};

if (typeof inputData === 'string') {
  html = inputData;
} else if (inputData.body) {
  html = inputData.body;
  headers = inputData.headers || {};
} else if (inputData.data) {
  html = inputData.data;
  headers = inputData.headers || {};
} else {
  throw new Error('Unexpected response structure: ' + JSON.stringify(Object.keys(inputData)));
}

const tokenMatch = html.match(/name="authenticity_token"[^>]*value="([^"]+)"/);
const csrfToken = tokenMatch ? tokenMatch[1] : '';

if (!csrfToken) {
  throw new Error('CSRF token not found in login page');
}

let cookies = '';
if (headers['set-cookie']) {
  const cookieArray = Array.isArray(headers['set-cookie']) 
    ? headers['set-cookie'] 
    : [headers['set-cookie']];
  cookies = cookieArray.map(c => c.split(';')[0]).join('; ');
}

const prevData = $('Set Config').first().json;

return [{
  json: {
    csrfToken,
    cookies,
    REDMINE_BASE_URL: prevData.REDMINE_BASE_URL,
    REDMINE_USERNAME: prevData.REDMINE_USERNAME,
    REDMINE_PASSWORD: prevData.REDMINE_PASSWORD,
    NOTION_DATABASE_ID: prevData.NOTION_DATABASE_ID,
    PERIOD_START: prevData.PERIOD_START,
    PERIOD_END: prevData.PERIOD_END,
    PERIOD_DISPLAY: prevData.PERIOD_DISPLAY,
    reportType: prevData.reportType,
    SLACK_CHANNELS: prevData.SLACK_CHANNELS,
    PROJECTS: prevData.PROJECTS
  }
}];

const response = $input.first().json;
const headers = response.headers || {};
const statusCode = response.statusCode;
const prevData = $('Extract CSRF Token').first().json;

if (statusCode !== 302) {
  throw new Error(`Login failed: Expected 302 redirect, got ${statusCode}`);
}

let sessionCookies = '';

if (headers['set-cookie']) {
  const cookieArray = Array.isArray(headers['set-cookie']) 
    ? headers['set-cookie'] 
    : [headers['set-cookie']];
  sessionCookies = cookieArray.map(c => c.split(';')[0]).join('; ');
}

if (!sessionCookies) {
  throw new Error('No session cookie received after login');
}

return [{
  json: {
    sessionCookies,
    PROJECTS: prevData.PROJECTS,
    PERIOD_START: prevData.PERIOD_START,
    PERIOD_END: prevData.PERIOD_END,
    PERIOD_DISPLAY: prevData.PERIOD_DISPLAY,
    reportType: prevData.reportType,
    REDMINE_BASE_URL: prevData.REDMINE_BASE_URL,
    NOTION_DATABASE_ID: prevData.NOTION_DATABASE_ID,
    SLACK_CHANNELS: prevData.SLACK_CHANNELS
  }
}];

const data = $input.first().json;
const projects = data.PROJECTS;

return projects.map(project => ({
  json: {
    projectName: project.name,
    projectUrl: project.url,
    sessionCookies: data.sessionCookies,
    PERIOD_START: data.PERIOD_START,
    PERIOD_END: data.PERIOD_END,
    PERIOD_DISPLAY: data.PERIOD_DISPLAY,
    reportType: data.reportType,
    REDMINE_BASE_URL: data.REDMINE_BASE_URL,
    NOTION_DATABASE_ID: data.NOTION_DATABASE_ID,
    SLACK_CHANNELS: data.SLACK_CHANNELS
  }
}));

const allInputItems = $input.all();
const allProjectItems = $('Split Projects').all();

// HTML 엔티티 디코딩 함수
function decodeHtmlEntities(str) {
  if (!str) return '';
  return str
    .replace(/&#x27;/g, "'")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec))
    .replace(/&#x([0-9a-fA-F]+);/g, (match, hex) => String.fromCharCode(parseInt(hex, 16)));
}

const results = [];

for (let idx = 0; idx < allInputItems.length; idx++) {
  const inputData = allInputItems[idx].json;
  const projectData = allProjectItems[idx]?.json || {};

  let html = '';
  if (typeof inputData === 'string') {
    html = inputData;
  } else if (inputData.data) {
    html = inputData.data;
  } else if (inputData.body) {
    html = inputData.body;
  } else {
    continue;
  }

  const issues = [];

  const issueIdRegex = /<tr[^>]*id="issue-(\d+)"[^>]*>/gi;
  const issueIds = [];
  let idMatch;
  while ((idMatch = issueIdRegex.exec(html)) !== null) {
    issueIds.push(idMatch[1]);
  }

  const extractAll = (regex) => {
    const matches = [];
    let match;
    while ((match = regex.exec(html)) !== null) {
      matches.push(match[1] ? match[1].trim() : '');
    }
    return matches;
  };

  const subjects = extractAll(/<td class="subject"><a[^>]*>([\s\S]*?)<\/a><\/td>/gi);
  const statuses = extractAll(/<td class="status">([^<]*)<\/td>/gi);
  const priorities = extractAll(/<td class="priority">([^<]*)<\/td>/gi);
  const dueDates = extractAll(/<td class="due_date"[^>]*>([^<]*)<\/td>/gi);
  const createdOns = extractAll(/<td class="created_on"[^>]*>([^<]*)<\/td>/gi);
  const cf44s = extractAll(/<td class="cf_44[^"]*"[^>]*>([^<]*)<\/td>/gi);
  const closedOns = extractAll(/<td class="closed_on"[^>]*>([^<]*)<\/td>/gi);
  const startDates = extractAll(/<td class="start_date"[^>]*>([^<]*)<\/td>/gi);

  const assignedTos = [];
  const assignedToRegex = /<td class="assigned_to"[^>]*>([\s\S]*?)<\/td>/gi;
  let assignedMatch;
  while ((assignedMatch = assignedToRegex.exec(html)) !== null) {
    const content = assignedMatch[1];
    const linkMatch = content.match(/<a[^>]*>([^<]*)<\/a>/);
    assignedTos.push(linkMatch ? linkMatch[1].trim() : (content.trim() || '미배정'));
  }

  const progresses = extractAll(/class="progress progress-(\d+)"/gi);

  for (let i = 0; i < issueIds.length; i++) {
    let completedDate = cf44s[i] || closedOns[i] || '';

    const issue = {
      '#': issueIds[i],
      'url': `${projectData.REDMINE_BASE_URL}/issues/${issueIds[i]}`,
      '제목': decodeHtmlEntities(subjects[i] || ''),
      '상태': statuses[i] || '',
      '우선순위': priorities[i] || '',
      '담당자': assignedTos[i] || '미배정',
      '완료기한': dueDates[i] || '',
      '등록': createdOns[i] || '',
      '완료일': completedDate,
      '진척도': progresses[i] ? parseInt(progresses[i]) : 0,
      '시작시간': startDates[i] || ''
    };
    issues.push(issue);
  }

  results.push({
    json: {
      projectName: projectData.projectName,
      projectUrl: projectData.projectUrl,
      issues,
      totalItems: issues.length,
      sessionCookies: projectData.sessionCookies,
      PERIOD_START: projectData.PERIOD_START,
      PERIOD_END: projectData.PERIOD_END,
      PERIOD_DISPLAY: projectData.PERIOD_DISPLAY,
      reportType: projectData.reportType,
      REDMINE_BASE_URL: projectData.REDMINE_BASE_URL,
      NOTION_DATABASE_ID: projectData.NOTION_DATABASE_ID,
      SLACK_CHANNELS: projectData.SLACK_CHANNELS
    }
  });
}

return results;

// 월간 이슈 분류: 신규, 처리완료, 처리중, 잔여
// 신규는 다른 상태와 중복 가능 (기간 내 등록 + 기간 내 완료 = 신규 1, 완료 1)
// 기준: PERIOD_START ~ PERIOD_END 기간 내
const allItems = $input.all();
const results = [];

const CLOSED_STATUSES = [
  '처리 완료',
  '처리 반려',
  '종료 [해결]',
  '종료 [미해결]',
  '종료 [폐기]',
  '종료 [테스트오류]'
];

const EXCLUDED_PRIORITIES = ['개선'];

for (let idx = 0; idx < allItems.length; idx++) {
  const data = allItems[idx].json;
  const issues = data.issues || [];
  const periodStart = data.PERIOD_START;
  const periodEnd = data.PERIOD_END;

  function normalizeDate(dateStr) {
    if (!dateStr) return '';
    const datePart = dateStr.split(' ')[0];
    return datePart.replace(/\//g, '-');
  }

  function toShortDate(dateStr) {
    if (!dateStr) return '-';
    const normalized = normalizeDate(dateStr);
    if (!normalized) return '-';
    const parts = normalized.split('-');
    if (parts.length === 3) {
      return `${parts[0].slice(-2)}/${parts[1]}/${parts[2]}`;
    }
    return dateStr;
  }

  function isClosedStatus(status) {
    return CLOSED_STATUSES.some(s => status.includes(s) || s.includes(status));
  }

  function isExcludedPriority(priority) {
    return EXCLUDED_PRIORITIES.includes(priority);
  }

  function isInPeriod(dateStr) {
    const normalized = normalizeDate(dateStr);
    if (!normalized) return false;
    return normalized >= periodStart && normalized <= periodEnd;
  }

  const classified = {
    신규: [],
    처리완료: [],
    처리중: [],
    잔여: []
  };

  issues.forEach((issue) => {
    const priority = issue['우선순위'] || '';

    if (isExcludedPriority(priority)) {
      return;
    }

    const registeredDate = normalizeDate(issue['등록']);
    const completedDate = normalizeDate(issue['완료일']);
    const progress = issue['진척도'] || 0;
    const status = issue['상태'] || '';

    const issueData = {
      id: issue['#'],
      url: `${data.REDMINE_BASE_URL}/issues/${issue['#']}`,
      제목: issue['제목'],
      우선순위: priority,
      담당자: issue['담당자'],
      완료기한: toShortDate(issue['완료기한']),
      완료일: toShortDate(issue['완료일']),
      상태: status,
      진척도: progress
    };

    // 1. 신규: 기간 내에 등록된 이슈 (독립적 체크 - 다른 상태와 중복 가능)
    if (isInPeriod(registeredDate)) {
      classified.신규.push({...issueData});
    }

    // 2. 처리완료: 기간 내에 완료 + 종료 상태
    if (isInPeriod(completedDate) && isClosedStatus(status)) {
      classified.처리완료.push({...issueData});
    }
    // 3. 처리중: 완료일 없음 + 진척도 10~79% + 종료 상태 아님
    else if (!completedDate && progress >= 10 && progress < 80 && !isClosedStatus(status)) {
      classified.처리중.push({...issueData});
    }
    // 4. 잔여: 진척도 80% 미만 + 완료 상태 아님
    else if (progress < 80 && !isClosedStatus(status)) {
      classified.잔여.push({...issueData});
    }
  });

  results.push({
    json: {
      projectName: data.projectName,
      classified,
      counts: {
        신규: classified.신규.length,
        처리완료: classified.처리완료.length,
        처리중: classified.처리중.length,
        잔여: classified.잔여.length
      },
      PERIOD_START: data.PERIOD_START,
      PERIOD_END: data.PERIOD_END,
      PERIOD_DISPLAY: data.PERIOD_DISPLAY,
      reportType: data.reportType,
      NOTION_DATABASE_ID: data.NOTION_DATABASE_ID,
      SLACK_CHANNELS: data.SLACK_CHANNELS
    }
  });
}

return results;

// 월간 리포트를 Notion API 형식으로 변환
const MAX_BLOCKS_PER_REQUEST = 100;

const allItems = $input.all();

let projectsData = [];

if (allItems.length > 0) {
  const firstItem = allItems[0].json;

  if (Array.isArray(firstItem.data)) {
    projectsData = firstItem.data;
  } else if (Array.isArray(firstItem.projectsData)) {
    projectsData = firstItem.projectsData;
  } else if (firstItem.projectName) {
    projectsData = allItems.map(item => item.json);
  } else {
    for (const key of Object.keys(firstItem)) {
      if (Array.isArray(firstItem[key]) && firstItem[key].length > 0) {
        const sample = firstItem[key][0];
        if (sample && sample.projectName) {
          projectsData = firstItem[key];
          break;
        }
      }
    }
  }
}

if (projectsData.length === 0) {
  throw new Error('No project data found. Check Aggregate node output.');
}

const periodDisplay = projectsData[0]?.PERIOD_DISPLAY || '';
const periodEnd = projectsData[0]?.PERIOD_END || new Date().toISOString().split('T')[0];
const notionDbId = projectsData[0]?.NOTION_DATABASE_ID;
const slackChannels = projectsData[0]?.SLACK_CHANNELS;

function formatIssue(issue, includeCompleted = false, includeAssignee = true) {
  let line = `#${issue.id} [${issue.우선순위}] ${issue.제목} (${issue.완료기한})`;
  if (includeCompleted && issue.완료일 && issue.완료일 !== '-') {
    line += ` 완료:${issue.완료일}`;
  }
  if (includeAssignee) {
    line += ` - ${issue.담당자}`;
  }
  return line;
}

function createRichText(text) {
  return [{ type: 'text', text: { content: text } }];
}

function createBulletItem(text, url = null) {
  const richText = url 
    ? [{ type: 'text', text: { content: text, link: { url: url } } }]
    : [{ type: 'text', text: { content: text } }];

  return {
    object: 'block',
    type: 'bulleted_list_item',
    bulleted_list_item: { rich_text: richText }
  };
}

function createIssueBlocks(issues, includeCompleted = false, includeAssignee = true) {
  if (!issues || issues.length === 0) {
    return [createBulletItem('(없음)')];
  }

  return issues.map(issue => {
    const text = formatIssue(issue, includeCompleted, includeAssignee);
    return createBulletItem(text, issue.url);
  });
}

let allChildren = [];

let slackSummary = [];
projectsData.forEach((project) => {
  const { projectName, counts } = project;
  if (counts) {
    slackSummary.push(`• ${projectName}: 신규 ${counts.신규}건 / 완료 ${counts.처리완료}건 / 처리중 ${counts.처리중}건 / 잔여 ${counts.잔여}건`);
  }
});

allChildren.push({
  object: 'block',
  type: 'callout',
  callout: {
    rich_text: createRichText(slackSummary.join('\n')),
    icon: { type: 'emoji', emoji: '📊' },
    color: 'green_background'
  }
});

allChildren.push({
  object: 'block',
  type: 'divider',
  divider: {}
});

projectsData.forEach((project, idx) => {
  const { projectName, classified, counts } = project;

  if (!classified || !counts) {
    return;
  }

  allChildren.push({
    object: 'block',
    type: 'heading_2',
    heading_2: {
      rich_text: createRichText(`${projectName} (신규 ${counts.신규}건, 완료 ${counts.처리완료}건, 처리중 ${counts.처리중}건, 잔여 ${counts.잔여}건)`)
    }
  });

  if (counts.신규 > 0) {
    allChildren.push({
      object: 'block',
      type: 'heading_3',
      heading_3: { rich_text: createRichText('📋 신규') }
    });
    allChildren.push(...createIssueBlocks(classified.신규, false, true));
  }

  if (counts.처리완료 > 0) {
    allChildren.push({
      object: 'block',
      type: 'heading_3',
      heading_3: { rich_text: createRichText('✅ 처리 완료') }
    });
    allChildren.push(...createIssueBlocks(classified.처리완료, true, true));
  }

  if (counts.처리중 > 0) {
    allChildren.push({
      object: 'block',
      type: 'heading_3',
      heading_3: { rich_text: createRichText('🔄 처리 중') }
    });
    allChildren.push(...createIssueBlocks(classified.처리중, false, true));
  }

  if (counts.잔여 > 0) {
    allChildren.push({
      object: 'block',
      type: 'heading_3',
      heading_3: { rich_text: createRichText('📝 잔여') }
    });
    allChildren.push(...createIssueBlocks(classified.잔여, false, true));
  }

  if (idx < projectsData.length - 1) {
    allChildren.push({
      object: 'block',
      type: 'divider',
      divider: {}
    });
  }
});

const childrenChunks = [];
for (let i = 0; i < allChildren.length; i += MAX_BLOCKS_PER_REQUEST) {
  childrenChunks.push(allChildren.slice(i, i + MAX_BLOCKS_PER_REQUEST));
}

const firstChunk = childrenChunks[0] || [];
const appendChunks = childrenChunks.slice(1);

const notionBody = {
  parent: { database_id: notionDbId },
  icon: {
    type: 'emoji',
    emoji: '📆'
  },
  properties: {
    Name: { title: [{ text: { content: `[PMS 월간 리포트] ${periodDisplay}` } }] },
    Date: { date: { start: periodEnd } },
    Tags: { select: { name: 'PMS-Monthly' } }
  },
  children: firstChunk
};

return [{
  json: {
    pageTitle: `[PMS 월간 리포트] ${periodDisplay}`,
    notionBody: notionBody,
    appendChunks: appendChunks,
    slackSummary: slackSummary.join('\n'),
    periodDisplay,
    NOTION_DATABASE_ID: notionDbId,
    SLACK_CHANNELS: slackChannels
  }
}];

const notionResponse = $input.first().json;
const reportData = $('Generate Report').first().json;

const pageId = notionResponse.id;
const appendChunks = reportData.appendChunks || [];

if (appendChunks.length === 0) {
  return [{
    json: {
      pageId,
      pageUrl: notionResponse.url,
      appendComplete: true,
      slackSummary: reportData.slackSummary,
      periodDisplay: reportData.periodDisplay,
      SLACK_CHANNELS: reportData.SLACK_CHANNELS,
      pageTitle: reportData.pageTitle
    }
  }];
}

return appendChunks.map((chunk, idx) => ({
  json: {
    pageId,
    pageUrl: notionResponse.url,
    chunkIndex: idx,
    chunkTotal: appendChunks.length,
    children: chunk,
    slackSummary: reportData.slackSummary,
    periodDisplay: reportData.periodDisplay,
    SLACK_CHANNELS: reportData.SLACK_CHANNELS,
    pageTitle: reportData.pageTitle
  }
}));

const allItems = $input.all();
const firstItem = allItems[0].json;

let pageUrl, slackSummary, periodDisplay, slackChannels, pageTitle;

if (firstItem.pageUrl) {
  pageUrl = firstItem.pageUrl;
  slackSummary = firstItem.slackSummary;
  periodDisplay = firstItem.periodDisplay;
  slackChannels = firstItem.SLACK_CHANNELS;
  pageTitle = firstItem.pageTitle;
} else {
  const reportData = $('Generate Report').first().json;
  const createResponse = $('Create Notion Page').first().json;
  pageUrl = createResponse.url;
  slackSummary = reportData.slackSummary;
  periodDisplay = reportData.periodDisplay;
  slackChannels = reportData.SLACK_CHANNELS;
  pageTitle = reportData.pageTitle;
}

return slackChannels.map(channel => ({
  json: {
    channel,
    slackSummary,
    periodDisplay,
    notionPageUrl: pageUrl,
    pageTitle
  }
}));
